package com.weeklycommit.ai.rag;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;
import java.util.Map;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

/**
 * Cross-encoder reranking service for the RAG pipeline.
 *
 * <p>
 * Sits between Pinecone retrieval and LLM context assembly. Takes a larger
 * candidate set (e.g. top-80 from Pinecone) and re-scores it to produce a
 * smaller, higher-quality top-N list for the answer generation step.
 *
 * <p>
 * Implementation priority (in order):
 * <ol>
 * <li><b>Disabled (default)</b> — when {@code ai.rerank.enabled=false} (the
 * default), reranking is skipped entirely. The top-N candidates are returned by
 * truncating the Pinecone result list by score, which is the same behaviour as
 * before reranking was added. Teams opt-in once a Cohere API key is
 * configured.</li>
 * <li><b>Cohere Rerank API</b> — preferred production path when
 * {@code ai.rerank.api-key} is set. Minimal latency overhead (~200 ms).</li>
 * <li><b>LLM-based batch reranking</b> — last-resort development/testing
 * fallback when Cohere is unavailable but reranking is explicitly enabled via
 * {@code ai.rerank.enabled=true}. This adds a third LLM call per RAG query
 * (intent + answer + rerank) and can add 5–30 s of latency. Do NOT enable in
 * production without a Cohere key.</li>
 * </ol>
 *
 * <p>
 * Graceful degradation: any failure in reranking falls back to the original
 * candidate list truncated to top-N.
 */
@Service
public class RerankService {

	private static final Logger log = LoggerFactory.getLogger(RerankService.class);

	private static final String COHERE_RERANK_URL = "https://api.cohere.ai/v1/rerank";
	private static final String COHERE_DEFAULT_MODEL = "rerank-english-v3.0";

	/**
	 * Maximum chunks to send per LLM-based rerank call to avoid massive prompts.
	 */
	private static final int LLM_RERANK_MAX_CHUNKS = 40;

	/** Suggestion type string for the LLM rerank batch call. */
	private static final String TYPE_RAG_RERANK = "RAG_RERANK";

	/**
	 * A chunk returned by the reranker, carrying both its original Pinecone score
	 * and its computed rerank score.
	 */
	public record RankedChunk(String id, double score, Map<String, Object> metadata, double rerankScore) {
	}

	// ── Configuration ─────────────────────────────────────────────────────

	private final boolean enabled;
	private final int topN;
	private final String cohereApiKey;

	// ── Dependencies ──────────────────────────────────────────────────────

	private final AiProviderRegistry aiProviderRegistry;
	private final ObjectMapper objectMapper;
	private final HttpClient httpClient;

	// ── Constructors ─────────────────────────────────────────────────────

	/**
	 * Spring-managed constructor.
	 *
	 * <p>
	 * Defaults: {@code ai.rerank.enabled=false} (opt-in),
	 * {@code ai.rerank.top-n=20}, {@code ai.rerank.api-key} empty (Cohere
	 * disabled).
	 */
	@Autowired
	public RerankService(@Value("${ai.rerank.enabled:false}") boolean enabled, @Value("${ai.rerank.top-n:20}") int topN,
			@Value("${ai.rerank.api-key:}") String cohereApiKey, AiProviderRegistry aiProviderRegistry,
			ObjectMapper objectMapper) {
		this(enabled, topN, cohereApiKey, aiProviderRegistry, objectMapper,
				HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build());
		if (enabled) {
			if (cohereApiKey != null && !cohereApiKey.isBlank()) {
				log.info("RerankService: Cohere reranking enabled (top-n={})", topN);
			} else {
				log.warn("RerankService: LLM-based reranking enabled (top-n={}) — this adds ~5-30 s latency per RAG "
						+ "query. Configure ai.rerank.api-key for Cohere Rerank instead.", topN);
			}
		} else {
			log.debug("RerankService: reranking disabled (pass-through mode)");
		}
	}

	/**
	 * Package-private constructor for unit tests — accepts a mock
	 * {@link HttpClient} so no real HTTP calls are made.
	 */
	RerankService(boolean enabled, int topN, String cohereApiKey, AiProviderRegistry aiProviderRegistry,
			ObjectMapper objectMapper, HttpClient httpClient) {
		this.enabled = enabled;
		this.topN = topN;
		this.cohereApiKey = cohereApiKey;
		this.aiProviderRegistry = aiProviderRegistry;
		this.objectMapper = objectMapper;
		this.httpClient = httpClient;
	}

	// ── Public API ────────────────────────────────────────────────────────

	/** Returns the configured top-N value (used by callers to size the result). */
	public int getTopN() {
		return topN;
	}

	/**
	 * Reranks the candidate chunks against the query and returns the
	 * top-{@code topN} results.
	 *
	 * <p>
	 * When reranking is disabled, this method truncates {@code candidates} to
	 * {@code topN} by their Pinecone score (pass-through). When reranking is
	 * enabled and fails for any reason, the same pass-through behaviour is applied
	 * and a warning is logged.
	 *
	 * @param query
	 *            the user's original question
	 * @param candidates
	 *            Pinecone retrieval results to rerank
	 * @param topN
	 *            maximum number of results to return
	 * @return reranked list capped at {@code topN}, never {@code null}
	 */
	public List<RankedChunk> rerank(String query, List<PineconeClient.PineconeMatch> candidates, int topN) {
		if (candidates == null || candidates.isEmpty()) {
			return List.of();
		}
		if (!enabled) {
			return passThrough(candidates, topN);
		}
		try {
			if (cohereApiKey != null && !cohereApiKey.isBlank()) {
				return rerankWithCohere(query, candidates, topN);
			} else {
				return rerankWithLlm(query, candidates, topN);
			}
		} catch (Exception e) {
			log.warn("RerankService: reranking failed — falling back to pass-through (top-{}): {}", topN,
					e.getMessage());
			return passThrough(candidates, topN);
		}
	}

	// ── Private: pass-through ────────────────────────────────────────────

	private List<RankedChunk> passThrough(List<PineconeClient.PineconeMatch> candidates, int topN) {
		return candidates.stream().limit(topN).map(m -> new RankedChunk(m.id(), m.score(), m.metadata(), m.score()))
				.toList();
	}

	// ── Private: Cohere Rerank API ───────────────────────────────────────

	/**
	 * Calls the Cohere Rerank API to score candidates against the query.
	 *
	 * <p>
	 * Sends all candidates to Cohere (which handles large lists efficiently) and
	 * maps the ranked results back to {@link RankedChunk} instances.
	 */
	private List<RankedChunk> rerankWithCohere(String query, List<PineconeClient.PineconeMatch> candidates, int topN)
			throws Exception {
		ObjectNode body = objectMapper.createObjectNode();
		body.put("query", query);
		body.put("model", COHERE_DEFAULT_MODEL);
		body.put("top_n", topN);
		body.put("return_documents", false);

		ArrayNode docs = body.putArray("documents");
		for (PineconeClient.PineconeMatch m : candidates) {
			String text = extractText(m);
			docs.add(text);
		}

		String json = objectMapper.writeValueAsString(body);
		HttpRequest req = HttpRequest.newBuilder().uri(URI.create(COHERE_RERANK_URL))
				.header("Authorization", "Bearer " + cohereApiKey).header("Content-Type", "application/json")
				.timeout(Duration.ofSeconds(20)).POST(HttpRequest.BodyPublishers.ofString(json)).build();

		HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
		if (resp.statusCode() != 200) {
			throw new IllegalStateException("Cohere API returned " + resp.statusCode() + ": " + resp.body());
		}

		JsonNode root = objectMapper.readTree(resp.body());
		JsonNode results = root.get("results");
		if (results == null || !results.isArray()) {
			throw new IllegalStateException("Cohere response missing 'results' array");
		}

		List<RankedChunk> ranked = new ArrayList<>(results.size());
		for (JsonNode result : results) {
			int index = result.path("index").asInt(-1);
			double score = result.path("relevance_score").asDouble(0.0);
			if (index >= 0 && index < candidates.size()) {
				PineconeClient.PineconeMatch original = candidates.get(index);
				ranked.add(new RankedChunk(original.id(), original.score(), original.metadata(), score));
			}
		}

		log.debug("RerankService: Cohere reranked {} → {} candidates", candidates.size(), ranked.size());
		return Collections.unmodifiableList(ranked);
	}

	// ── Private: LLM-based batch reranking ──────────────────────────────

	/**
	 * Uses the LLM as a last-resort batch reranker.
	 *
	 * <p>
	 * Sends up to {@value #LLM_RERANK_MAX_CHUNKS} chunks in a single LLM call and
	 * asks it to return relevance scores as a JSON array. This is ONE LLM call
	 * regardless of the number of chunks. However, it adds significant latency
	 * (typically 5–30 s) compared to Cohere (~200 ms).
	 */
	private List<RankedChunk> rerankWithLlm(String query, List<PineconeClient.PineconeMatch> candidates, int topN)
			throws Exception {
		// Safety cap to keep the prompt manageable
		List<PineconeClient.PineconeMatch> batch = candidates.size() > LLM_RERANK_MAX_CHUNKS
				? candidates.subList(0, LLM_RERANK_MAX_CHUNKS)
				: candidates;

		// Build document list for the prompt
		List<Map<String, Object>> documents = new ArrayList<>(batch.size());
		for (int i = 0; i < batch.size(); i++) {
			documents.add(Map.of("index", i, "text", extractText(batch.get(i))));
		}

		Map<String, Object> additionalContext = Map.of("task",
				"Relevance ranking: rate each document's relevance to the query", "instruction",
				"Return ONLY valid JSON: {\"rankings\": [{\"chunkIndex\": 0, \"score\": 0.0}, ...]}", "query", query,
				"documents", documents);

		AiContext ctx = new AiContext(TYPE_RAG_RERANK, null, null, null, Map.of(), Map.of(), List.of(), List.of(),
				additionalContext);
		AiSuggestionResult result = aiProviderRegistry.generateSuggestion(ctx);

		if (!result.available()) {
			throw new IllegalStateException("LLM rerank call returned unavailable");
		}

		// Parse ranking scores from the LLM response
		JsonNode root = objectMapper.readTree(result.payload());
		JsonNode rankingsNode = root.get("rankings");
		if (rankingsNode == null || !rankingsNode.isArray()) {
			throw new IllegalStateException("LLM rerank response missing 'rankings' array");
		}

		// Build a score map from chunkIndex → score
		Map<Integer, Double> scores = new java.util.HashMap<>();
		for (JsonNode rn : rankingsNode) {
			int idx = rn.path("chunkIndex").asInt(-1);
			double score = rn.path("score").asDouble(0.0);
			if (idx >= 0) {
				scores.put(idx, score);
			}
		}

		// Map scores back to candidates, sort by score descending, take topN
		List<RankedChunk> ranked = new ArrayList<>(batch.size());
		for (int i = 0; i < batch.size(); i++) {
			PineconeClient.PineconeMatch m = batch.get(i);
			double rerankScore = scores.getOrDefault(i, 0.0);
			ranked.add(new RankedChunk(m.id(), m.score(), m.metadata(), rerankScore));
		}
		ranked.sort(Comparator.comparingDouble(RankedChunk::rerankScore).reversed());

		List<RankedChunk> result2 = ranked.stream().limit(topN).toList();
		log.debug("RerankService: LLM reranked {} → {} candidates", batch.size(), result2.size());
		return result2;
	}

	// ── Private helpers ──────────────────────────────────────────────────

	/**
	 * Extracts a text representation from a Pinecone match for use as a reranking
	 * document. Tries the {@code "text"} metadata field first (set by
	 * {@code SemanticIndexService.upsertChunk()}), falling back to the chunk ID.
	 */
	private String extractText(PineconeClient.PineconeMatch match) {
		if (match.metadata() != null) {
			Object text = match.metadata().get("text");
			if (text instanceof String s && !s.isBlank()) {
				// Truncate very long texts to keep request sizes reasonable
				return s.length() > 500 ? s.substring(0, 500) : s;
			}
		}
		return match.id();
	}
}

package com.weeklycommit.ai.rag;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.ai.service.AiSuggestionService;
import com.weeklycommit.domain.entity.Team;
import com.weeklycommit.domain.repository.TeamRepository;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

/**
 * Handles semantic (RAG) queries: embeds the question, retrieves relevant
 * chunks from Pinecone, and synthesises an answer via the LLM.
 *
 * <p>
 * Pipeline:
 * <ol>
 * <li>Intent classification — extracts entity-type filters and time-range from
 * the natural-language question.</li>
 * <li>Embedding — converts the question to a dense vector.</li>
 * <li>Pinecone retrieval — nearest-neighbour search with metadata filters.</li>
 * <li>Answer generation — packs retrieved chunks into a RAG prompt and calls
 * the LLM.</li>
 * <li>Audit — persists the interaction via {@link AiSuggestionService}.</li>
 * </ol>
 *
 * <p>
 * All steps degrade gracefully: if any upstream service is unavailable, the
 * method returns an unavailable {@link RagQueryResult} without throwing.
 */
@Service
public class SemanticQueryService {

	private static final Logger log = LoggerFactory.getLogger(SemanticQueryService.class);
	/**
	 * Retrieve more candidates from Pinecone; the reranker filters down to top-N.
	 */
	private static final int TOP_K = 80;

	// ── Inner records ─────────────────────────────────────────────────────

	/**
	 * A single source item that contributed to a RAG answer.
	 *
	 * @param entityType
	 *            e.g. {@code "commit"}, {@code "plan_summary"}
	 * @param entityId
	 *            the entity UUID string
	 * @param weekStartDate
	 *            ISO week-start date extracted from vector metadata (may be empty)
	 * @param snippet
	 *            brief excerpt from the chunk text
	 */
	public record RagSource(String entityType, String entityId, String weekStartDate, String snippet) {
	}

	/**
	 * Result of a RAG query.
	 *
	 * @param available
	 *            {@code false} if any upstream dependency is unavailable
	 * @param answer
	 *            synthesised natural-language answer (null when unavailable)
	 * @param sources
	 *            retrieved chunks that informed the answer
	 * @param confidence
	 *            model confidence [0.0, 1.0]
	 * @param suggestionId
	 *            ID of the persisted
	 *            {@link com.weeklycommit.domain.entity.AiSuggestion} audit record
	 *            (null when unavailable)
	 */
	public record RagQueryResult(boolean available, String answer, List<RagSource> sources, double confidence,
			UUID suggestionId) {

		/** Convenience factory for a degraded/unavailable result. */
		public static RagQueryResult unavailable() {
			return new RagQueryResult(false, null, List.of(), 0.0, null);
		}
	}

	// ── Dependencies ──────────────────────────────────────────────────────

	private final PineconeClient pineconeClient;
	private final EmbeddingService embeddingService;
	private final AiProviderRegistry aiProviderRegistry;
	private final AiSuggestionService aiSuggestionService;
	private final ObjectMapper objectMapper;
	private final TeamRepository teamRepo;
	private final SparseEncoder sparseEncoder;
	private final RerankService rerankService;

	public SemanticQueryService(PineconeClient pineconeClient, EmbeddingService embeddingService,
			AiProviderRegistry aiProviderRegistry, AiSuggestionService aiSuggestionService, ObjectMapper objectMapper,
			TeamRepository teamRepo, SparseEncoder sparseEncoder, RerankService rerankService) {
		this.pineconeClient = pineconeClient;
		this.embeddingService = embeddingService;
		this.aiProviderRegistry = aiProviderRegistry;
		this.aiSuggestionService = aiSuggestionService;
		this.objectMapper = objectMapper;
		this.teamRepo = teamRepo;
		this.sparseEncoder = sparseEncoder;
		this.rerankService = rerankService;
	}

	// ── Public API ────────────────────────────────────────────────────────

	/**
	 * Executes a RAG query for the given question scoped to a team.
	 *
	 * @param question
	 *            natural-language question from the user
	 * @param teamId
	 *            team scope for Pinecone namespace + metadata filter
	 * @param userId
	 *            requesting user (for audit)
	 * @return query result, never {@code null}; check
	 *         {@link RagQueryResult#available()}
	 */
	public RagQueryResult query(String question, UUID teamId, UUID userId) {
		if (!pineconeClient.isAvailable() || !embeddingService.isAvailable()) {
			log.debug("SemanticQueryService: unavailable (pinecone={}, embedding={})", pineconeClient.isAvailable(),
					embeddingService.isAvailable());
			return RagQueryResult.unavailable();
		}
		if (question == null || question.isBlank()) {
			return RagQueryResult.unavailable();
		}

		try {
			// Step 2: intent classification
			IntentResult intent = classifyIntent(question, teamId, userId);

			// Step 3: embed the question
			float[] vector = embeddingService.embed(question);
			if (vector.length == 0) {
				log.debug("SemanticQueryService: embedding returned empty vector — unavailable");
				return RagQueryResult.unavailable();
			}

			// Step 4: build metadata filter
			Map<String, Object> filter = buildFilter(intent, teamId, userId);

			// Step 5: query Pinecone with hybrid sparse+dense when available
			String namespace = resolveNamespace(teamId);
			java.util.Map<Integer, Float> sparseVector = null;
			try {
				java.util.Map<Integer, Float> sv = sparseEncoder.encode(question);
				if (!sv.isEmpty()) {
					sparseVector = sv;
				}
			} catch (Exception ex) {
				log.debug("SemanticQueryService: sparse encoding failed — falling back to dense-only: {}",
						ex.getMessage());
			}
			List<PineconeClient.PineconeMatch> matches = pineconeClient.query(namespace, vector, TOP_K, filter,
					sparseVector);

			// Step 5b: rerank candidates to find the most relevant top-N
			List<RerankService.RankedChunk> reranked = rerankService.rerank(question, matches, rerankService.getTopN());

			// Step 6 & 7: build RAG prompt context from reranked results and generate
			// answer
			String contextString = buildContextString(question, matches);
			AiContext ragContext = new AiContext(AiContext.TYPE_RAG_QUERY, userId, null, null, Map.of(), Map.of(),
					List.of(), List.of(), buildRagAdditionalContextReranked(question, reranked));
			AiSuggestionResult llmResult = aiProviderRegistry.generateSuggestion(ragContext);

			// Step 7: parse the answer
			RagAnswer ragAnswer = parseRagAnswer(llmResult);

			// Step 8: persist audit record
			com.weeklycommit.domain.entity.AiSuggestion stored = null;
			try {
				stored = aiSuggestionService.storeSuggestion(AiContext.TYPE_RAG_QUERY, userId, null, null,
						contextString, llmResult);
			} catch (Exception ex) {
				log.warn("SemanticQueryService: failed to store suggestion audit record — {}", ex.getMessage());
			}

			// Step 9: return result
			UUID suggestionId = stored != null ? stored.getId() : null;
			return new RagQueryResult(true, ragAnswer.answer(), ragAnswer.sources(), ragAnswer.confidence(),
					suggestionId);

		} catch (Exception e) {
			log.warn("SemanticQueryService: query failed — {}", e.getMessage());
			return RagQueryResult.unavailable();
		}
	}

	// ── Private pipeline steps ────────────────────────────────────────────

	/**
	 * Calls the LLM for intent classification. Returns safe defaults if the LLM
	 * call fails or returns unparseable JSON.
	 */
	private IntentResult classifyIntent(String question, UUID teamId, UUID userId) {
		try {
			String today = LocalDate.now().toString();
			// Last Monday = the previous Monday relative to today
			LocalDate todayDate = LocalDate.now();
			LocalDate lastMonday = todayDate.with(java.time.DayOfWeek.MONDAY).minusWeeks(1);
			String lastWeekFrom = lastMonday.toString();
			String lastWeekTo = lastMonday.plusDays(6).toString();
			String thisWeekFrom = todayDate.with(java.time.DayOfWeek.MONDAY).toString();
			Map<String, Object> additionalCtx = new HashMap<>();
			additionalCtx.put("question", question);
			additionalCtx.put("teamId", teamId != null ? teamId.toString() : "");
			additionalCtx.put("currentDate", today);
			additionalCtx.put("lastWeekFrom", lastWeekFrom);
			additionalCtx.put("lastWeekTo", lastWeekTo);
			additionalCtx.put("thisWeekFrom", thisWeekFrom);
			AiContext intentContext = new AiContext(AiContext.TYPE_RAG_INTENT, userId, null, null, Map.of(), Map.of(),
					List.of(), List.of(), additionalCtx);
			AiSuggestionResult result = aiProviderRegistry.generateSuggestion(intentContext);
			if (!result.available()) {
				return IntentResult.defaults();
			}
			return parseIntentResult(result.payload());
		} catch (Exception e) {
			log.debug("SemanticQueryService: intent classification failed — {}", e.getMessage());
			return IntentResult.defaults();
		}
	}

	private IntentResult parseIntentResult(String payload) {
		try {
			JsonNode root = objectMapper.readTree(payload);
			List<String> entityTypes = new ArrayList<>();
			JsonNode et = root.path("entityTypes");
			if (et.isArray()) {
				for (JsonNode node : et) {
					entityTypes.add(node.asText());
				}
			}
			List<String> keywords = new ArrayList<>();
			JsonNode kw = root.path("keywords");
			if (kw.isArray()) {
				for (JsonNode node : kw) {
					keywords.add(node.asText());
				}
			}
			JsonNode timeRange = root.path("timeRange");
			String from = timeRange.isObject() ? timeRange.path("from").asText(null) : null;
			String to = timeRange.isObject() ? timeRange.path("to").asText(null) : null;
			String intent = root.path("intent").asText("");
			String userFilter = root.path("userFilter").isMissingNode() || root.path("userFilter").isNull()
					? null
					: root.path("userFilter").asText(null);
			return new IntentResult(intent, userFilter, entityTypes, from, to, keywords);
		} catch (Exception e) {
			log.debug("SemanticQueryService: could not parse intent — using defaults");
			return IntentResult.defaults();
		}
	}

	private Map<String, Object> buildFilter(IntentResult intent, UUID teamId, UUID userId) {
		Map<String, Object> filter = new HashMap<>();
		if (teamId != null) {
			filter.put("teamId", teamId.toString());
		}
		if (intent.userFilter() != null && userId != null
				&& ("self".equalsIgnoreCase(intent.userFilter()) || "me".equalsIgnoreCase(intent.userFilter()))) {
			filter.put("userId", userId.toString());
		}
		// Entity type filter: use $in for multi-type queries.
		if (intent.entityTypes() != null && !intent.entityTypes().isEmpty()) {
			if (intent.entityTypes().size() == 1) {
				filter.put("entityType", intent.entityTypes().get(0));
			} else {
				filter.put("entityType", Map.of("$in", intent.entityTypes()));
			}
		}
		// Date range filter using the numeric weekStartEpochDay field.
		// ISO date strings ("YYYY-MM-DD") are not supported by Pinecone's $gte/$lte,
		// but the equivalent epoch-day long is stored alongside each chunk.
		Map<String, Object> dateRange = new HashMap<>();
		if (intent.timeRangeFrom() != null && !intent.timeRangeFrom().isBlank()) {
			Long epochFrom = ChunkBuilder.toEpochDay(intent.timeRangeFrom());
			if (epochFrom != null)
				dateRange.put("$gte", epochFrom);
		}
		if (intent.timeRangeTo() != null && !intent.timeRangeTo().isBlank()) {
			Long epochTo = ChunkBuilder.toEpochDay(intent.timeRangeTo());
			if (epochTo != null)
				dateRange.put("$lte", epochTo);
		}
		if (!dateRange.isEmpty()) {
			filter.put("weekStartEpochDay", dateRange);
		}
		return filter.isEmpty() ? null : filter;
	}

	private String resolveNamespace(UUID teamId) {
		if (teamId == null) {
			return "";
		}
		return teamRepo.findById(teamId).map(Team::getOrganizationId)
				.map(orgId -> orgId != null ? orgId.toString() : "").orElse("");
	}

	private String buildContextString(String question, List<PineconeClient.PineconeMatch> matches) {
		try {
			Map<String, Object> ctx = new HashMap<>();
			ctx.put("question", question);
			ctx.put("retrievedChunks", matches.size());
			return objectMapper.writeValueAsString(ctx);
		} catch (Exception e) {
			return "{\"question\":\"" + question + "\"}";
		}
	}

	private Map<String, Object> buildRagAdditionalContext(String question, List<PineconeClient.PineconeMatch> matches) {
		List<Map<String, Object>> chunks = matches.stream().map(m -> {
			Map<String, Object> chunk = new HashMap<>();
			chunk.put("id", m.id());
			chunk.put("score", m.score());
			chunk.put("metadata", m.metadata());
			return chunk;
		}).toList();
		Map<String, Object> ctx = new HashMap<>();
		ctx.put("question", question);
		ctx.put("currentDate", LocalDate.now().toString());
		ctx.put("retrievedChunks", chunks);
		return ctx;
	}

	/**
	 * Builds the additional context map for the RAG prompt using the reranked top-N
	 * chunks. Includes the rerank score so the LLM can see which chunks were most
	 * relevant.
	 */
	private Map<String, Object> buildRagAdditionalContextReranked(String question,
			List<RerankService.RankedChunk> reranked) {
		List<Map<String, Object>> chunks = reranked.stream().map(rc -> {
			Map<String, Object> chunk = new HashMap<>();
			chunk.put("id", rc.id());
			chunk.put("score", rc.score());
			chunk.put("rerankScore", rc.rerankScore());
			chunk.put("metadata", rc.metadata());
			return chunk;
		}).toList();
		Map<String, Object> ctx = new HashMap<>();
		ctx.put("question", question);
		ctx.put("currentDate", java.time.LocalDate.now().toString());
		ctx.put("retrievedChunks", chunks);
		return ctx;
	}

	private RagAnswer parseRagAnswer(AiSuggestionResult result) {
		if (!result.available()) {
			return new RagAnswer("AI provider unavailable", List.of(), 0.0);
		}
		try {
			JsonNode root = objectMapper.readTree(result.payload());
			String answer = root.path("answer").asText("No answer generated");
			double confidence = root.path("confidence").asDouble(0.0);

			List<RagSource> sources = new ArrayList<>();
			JsonNode sourcesNode = root.path("sources");
			if (sourcesNode.isArray()) {
				for (JsonNode s : sourcesNode) {
					sources.add(new RagSource(s.path("entityType").asText(""), s.path("entityId").asText(""),
							s.path("weekStartDate").asText(""), s.path("snippet").asText("")));
				}
			}
			return new RagAnswer(answer, sources, confidence);
		} catch (Exception e) {
			log.debug("SemanticQueryService: could not parse RAG answer — {}", e.getMessage());
			return new RagAnswer(result.payload(), List.of(), result.confidence());
		}
	}

	// ── Private helper records ────────────────────────────────────────────

	private record IntentResult(String intent, String userFilter, List<String> entityTypes, String timeRangeFrom,
			String timeRangeTo, List<String> keywords) {

		static IntentResult defaults() {
			return new IntentResult("", null, List.of(), null, null, List.of());
		}
	}

	private record RagAnswer(String answer, List<RagSource> sources, double confidence) {
	}
}

package com.weeklycommit.ai.rag;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import java.io.IOException;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.List;
import java.util.Map;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

/**
 * Unit tests for {@link RerankService}.
 *
 * <p>
 * Tests the three reranking paths: pass-through (disabled), LLM-based, and
 * Cohere. All HTTP calls are intercepted via a mock {@link HttpClient}.
 */
@ExtendWith(MockitoExtension.class)
class RerankServiceTest {

	private final ObjectMapper objectMapper = new ObjectMapper();

	@Mock
	private AiProviderRegistry aiProviderRegistry;

	@Mock
	private HttpClient httpClient;

	@Mock
	@SuppressWarnings("unchecked")
	private HttpResponse<String> httpResponse;

	// ── Feature flag disabled → pass-through ────────────────────────────

	@Test
	void rerank_disabled_returnsTruncatedByPineconeScore() {
		RerankService service = makeService(false, 2, "");

		List<PineconeClient.PineconeMatch> candidates = List.of(new PineconeClient.PineconeMatch("a", 0.9, Map.of()),
				new PineconeClient.PineconeMatch("b", 0.8, Map.of()),
				new PineconeClient.PineconeMatch("c", 0.7, Map.of()));

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 2);

		assertThat(result).hasSize(2);
		assertThat(result.get(0).id()).isEqualTo("a");
		assertThat(result.get(1).id()).isEqualTo("b");
		// No HTTP or LLM calls when disabled
		verify(aiProviderRegistry, never()).generateSuggestion(any());
	}

	@Test
	void rerank_disabled_topNGreaterThanCandidates_returnsAll() {
		RerankService service = makeService(false, 10, "");

		List<PineconeClient.PineconeMatch> candidates = List.of(new PineconeClient.PineconeMatch("a", 0.9, Map.of()),
				new PineconeClient.PineconeMatch("b", 0.8, Map.of()));

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 10);

		assertThat(result).hasSize(2);
	}

	@Test
	void rerank_disabled_passThroughUsesOriginalScoreAsRerankScore() {
		RerankService service = makeService(false, 5, "");

		List<PineconeClient.PineconeMatch> candidates = List
				.of(new PineconeClient.PineconeMatch("doc-1", 0.77, Map.of()));

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 5);

		assertThat(result.get(0).rerankScore()).isEqualTo(0.77);
	}

	// ── Empty candidates ─────────────────────────────────────────────────

	@Test
	void rerank_emptyCandidates_returnsEmptyList() {
		RerankService service = makeService(false, 5, "");

		List<RerankService.RankedChunk> result = service.rerank("query", List.of(), 5);

		assertThat(result).isEmpty();
	}

	@Test
	void rerank_nullCandidates_returnsEmptyList() {
		RerankService service = makeService(false, 5, "");

		List<RerankService.RankedChunk> result = service.rerank("query", null, 5);

		assertThat(result).isEmpty();
	}

	// ── LLM-based reranking (enabled, no Cohere key) ────────────────────

	@Test
	void rerank_llmEnabled_reordersChunksByScore() throws Exception {
		RerankService service = makeService(true, 3, "");

		List<PineconeClient.PineconeMatch> candidates = List.of(
				new PineconeClient.PineconeMatch("low", 0.5, Map.of("text", "unrelated document")),
				new PineconeClient.PineconeMatch("high", 0.6, Map.of("text", "very relevant document")),
				new PineconeClient.PineconeMatch("mid", 0.55, Map.of("text", "somewhat relevant")));

		// LLM scores chunk at index 1 highest
		String llmPayload = """
				{"rankings": [
				  {"chunkIndex": 0, "score": 0.1},
				  {"chunkIndex": 1, "score": 0.95},
				  {"chunkIndex": 2, "score": 0.5}
				]}
				""";
		when(aiProviderRegistry.generateSuggestion(any()))
				.thenReturn(new AiSuggestionResult(true, llmPayload, "rerank", 0.9, "stub-v1"));

		List<RerankService.RankedChunk> result = service.rerank("relevant question", candidates, 3);

		assertThat(result).hasSize(3);
		// Must be sorted by rerank score descending
		assertThat(result.get(0).id()).isEqualTo("high");
		assertThat(result.get(0).rerankScore()).isEqualTo(0.95);
		assertThat(result.get(1).id()).isEqualTo("mid");
		assertThat(result.get(2).id()).isEqualTo("low");
	}

	@Test
	void rerank_llmEnabled_truncatesToTopN() throws Exception {
		RerankService service = makeService(true, 2, "");

		List<PineconeClient.PineconeMatch> candidates = List.of(new PineconeClient.PineconeMatch("a", 0.9, Map.of()),
				new PineconeClient.PineconeMatch("b", 0.8, Map.of()),
				new PineconeClient.PineconeMatch("c", 0.7, Map.of()));

		String llmPayload = """
				{"rankings": [
				  {"chunkIndex": 0, "score": 0.3},
				  {"chunkIndex": 1, "score": 0.9},
				  {"chunkIndex": 2, "score": 0.6}
				]}
				""";
		when(aiProviderRegistry.generateSuggestion(any()))
				.thenReturn(new AiSuggestionResult(true, llmPayload, "rerank", 0.9, "stub-v1"));

		List<RerankService.RankedChunk> result = service.rerank("question", candidates, 2);

		assertThat(result).hasSize(2);
		assertThat(result.get(0).id()).isEqualTo("b"); // score 0.9
		assertThat(result.get(1).id()).isEqualTo("c"); // score 0.6
	}

	// ── Graceful fallback on failure ─────────────────────────────────────

	@Test
	void rerank_llmReturnsUnavailable_fallsBackToPassThrough() {
		RerankService service = makeService(true, 2, "");

		List<PineconeClient.PineconeMatch> candidates = List.of(new PineconeClient.PineconeMatch("x", 0.9, Map.of()),
				new PineconeClient.PineconeMatch("y", 0.7, Map.of()),
				new PineconeClient.PineconeMatch("z", 0.5, Map.of()));

		when(aiProviderRegistry.generateSuggestion(any())).thenReturn(AiSuggestionResult.unavailable());

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 2);

		// Falls back to pass-through: top-2 by original score
		assertThat(result).hasSize(2);
		assertThat(result.get(0).id()).isEqualTo("x");
		assertThat(result.get(1).id()).isEqualTo("y");
	}

	@Test
	void rerank_llmReturnsMalformedJson_fallsBackToPassThrough() {
		RerankService service = makeService(true, 2, "");

		List<PineconeClient.PineconeMatch> candidates = List.of(new PineconeClient.PineconeMatch("a", 0.9, Map.of()),
				new PineconeClient.PineconeMatch("b", 0.8, Map.of()));

		when(aiProviderRegistry.generateSuggestion(any()))
				.thenReturn(new AiSuggestionResult(true, "{\"unexpected\":\"shape\"}", "rerank", 0.5, "stub-v1"));

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 2);

		// Falls back to pass-through
		assertThat(result).hasSize(2);
		assertThat(result.get(0).id()).isEqualTo("a");
	}

	// ── Cohere reranking (enabled + api key) ─────────────────────────────

	@Test
	void rerank_cohereEnabled_reordersChunksByRelevanceScore() throws Exception {
		RerankService service = makeService(true, 2, "cohere-test-key");

		List<PineconeClient.PineconeMatch> candidates = List.of(
				new PineconeClient.PineconeMatch("doc-low", 0.5, Map.of("text", "unrelated")),
				new PineconeClient.PineconeMatch("doc-high", 0.6, Map.of("text", "highly relevant")));

		// Cohere returns: index 1 is most relevant
		String cohereResp = """
				{"results": [
				  {"index": 1, "relevance_score": 0.97},
				  {"index": 0, "relevance_score": 0.12}
				]}
				""";
		when(httpResponse.statusCode()).thenReturn(200);
		when(httpResponse.body()).thenReturn(cohereResp);
		when(httpClient.send(any(HttpRequest.class), any())).thenAnswer(inv -> httpResponse);

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 2);

		assertThat(result).hasSize(2);
		assertThat(result.get(0).id()).isEqualTo("doc-high");
		assertThat(result.get(0).rerankScore()).isEqualTo(0.97);
		assertThat(result.get(1).id()).isEqualTo("doc-low");
		// No LLM call was made
		verify(aiProviderRegistry, never()).generateSuggestion(any());
	}

	@Test
	void rerank_cohereHttpError_fallsBackToPassThrough() throws Exception {
		RerankService service = makeService(true, 2, "cohere-test-key");

		List<PineconeClient.PineconeMatch> candidates = List.of(new PineconeClient.PineconeMatch("a", 0.9, Map.of()),
				new PineconeClient.PineconeMatch("b", 0.7, Map.of()),
				new PineconeClient.PineconeMatch("c", 0.5, Map.of()));

		when(httpResponse.statusCode()).thenReturn(429);
		when(httpResponse.body()).thenReturn("{\"error\":\"rate limit\"}");
		when(httpClient.send(any(HttpRequest.class), any())).thenAnswer(inv -> httpResponse);

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 2);

		// Falls back to pass-through
		assertThat(result).hasSize(2);
		assertThat(result.get(0).id()).isEqualTo("a");
	}

	@Test
	void rerank_cohereNetworkError_fallsBackToPassThrough() throws Exception {
		RerankService service = makeService(true, 2, "cohere-test-key");

		List<PineconeClient.PineconeMatch> candidates = List.of(new PineconeClient.PineconeMatch("a", 0.9, Map.of()));
		when(httpClient.send(any(HttpRequest.class), any())).thenThrow(new IOException("Connection refused"));

		List<RerankService.RankedChunk> result = service.rerank("query", candidates, 1);

		assertThat(result).hasSize(1);
		assertThat(result.get(0).id()).isEqualTo("a");
	}

	// ── getTopN ──────────────────────────────────────────────────────────

	@Test
	void getTopN_returnsConfiguredValue() {
		RerankService service = makeService(false, 15, "");
		assertThat(service.getTopN()).isEqualTo(15);
	}

	// ── Helpers ──────────────────────────────────────────────────────────

	private RerankService makeService(boolean enabled, int topN, String cohereKey) {
		return new RerankService(enabled, topN, cohereKey, aiProviderRegistry, objectMapper, httpClient);
	}
}

